export const ProductListPanel = memo(function ProductListPanel({
  onCreateProduct,
  onCreateFromDraft,
  activeDrafts,
  page,
  totalPages,
  setPage,
  pageSize,
  setPageSize,
  nameLocale,
  setNameLocale,
  languageOptions,
  currencyCode,
  setCurrencyCode,
  currencyOptions,
  catalogFilter,
  setCatalogFilter,
  catalogs,
  loadError,
  actionError,
  onDismissActionError,
  search,
  setSearch,
  sku,
  setSku,
  minPrice,
  setMinPrice,
  maxPrice,
  setMaxPrice,
  startDate,
  setStartDate,
  endDate,
  setEndDate,
  data,
  rowSelection,
  setRowSelection,
  onSelectAllGlobal,
  loadingGlobal,
  onDeleteSelected,
  onAddToMarketplace,
  handleProductsTableRender,
  tableColumns,
  setRefreshTrigger,
  productNameKey,
  priceGroups,
  onProductNameClick,
  onProductEditClick,
  onIntegrationsClick,
  onExportSettingsClick,
  integrationBadgeIds,
  integrationBadgeStatuses,
  getRowId,
  isLoading,
  skeletonRows,
}: ProductListPanelProps) {
  const headerProps = useMemo(
    () => ({
      onCreateProduct,
      onCreateFromDraft,
      activeDrafts,
      page,
      totalPages,
      setPage,
      pageSize,
      setPageSize,
      nameLocale,
      setNameLocale,
      languageOptions,
      currencyCode,
      setCurrencyCode,
      currencyOptions,
      catalogFilter,
      setCatalogFilter,
      catalogs,
    }),
    [
      onCreateProduct,
      onCreateFromDraft,
      activeDrafts,
      page,
      totalPages,
      setPage,
      pageSize,
      setPageSize,
      nameLocale,
      setNameLocale,
      languageOptions,
      currencyCode,
      setCurrencyCode,
      currencyOptions,
      catalogFilter,
      setCatalogFilter,
      catalogs,
    ]
  );

  const filtersProps = useMemo(
    () => ({
      search,
      setSearch,
      sku,
      setSku,
      minPrice,
      setMinPrice,
      maxPrice,
      setMaxPrice,
      startDate,
      setStartDate,
      endDate,
      setEndDate,
    }),
    [
      search,
      setSearch,
      sku,
      setSku,
      minPrice,
      setMinPrice,
      maxPrice,
      setMaxPrice,
      startDate,
      setStartDate,
      endDate,
      setEndDate,
    ]
  );

  const tableProps = useMemo(
    () => ({
      columns: tableColumns,
      data,
      setRefreshTrigger,
      productNameKey,
      currencyCode,
      priceGroups,
      onProductNameClick,
      onProductEditClick,
      onIntegrationsClick,
      onExportSettingsClick,
      integrationBadgeIds,
      integrationBadgeStatuses,
      getRowId,
      rowSelection,
      onRowSelectionChange: setRowSelection,
      isLoading,
      skeletonRows,
    }),
    [
      tableColumns,
      data,
      setRefreshTrigger,
      productNameKey,
      currencyCode,
      priceGroups,
      onProductNameClick,
      onProductEditClick,
      onIntegrationsClick,
      onExportSettingsClick,
      integrationBadgeIds,
      integrationBadgeStatuses,
      getRowId,
      rowSelection,
      setRowSelection,
      isLoading,
      skeletonRows,
    ]
  );

  const alerts = useMemo(() => {
    if (!loadError && !actionError) return null;
    return (
