export function ProductModals({
  isCreateOpen,
  initialSku,
  createDraft,
  onCloseCreate,
  onCreateSuccess,
  editingProduct,
  onCloseEdit,
  onEditSuccess,
  onEditSave,
  integrationsProduct,
  onCloseIntegrations,
  onStartListing,
  showListProductModal,
  onCloseListProduct,
  onListProductSuccess,
  listProductPreset,
  exportSettingsProduct,
  onCloseExportSettings,
  onListingsUpdated,
  massListIntegration,
  massListProductIds,
  onCloseMassList,
  onMassListSuccess,
}: ProductModalsProps) {
  return (
    <>
      <AppModal
        open={isCreateOpen}
        onOpenChange={(open) => !open && onCloseCreate()}
        title="Create Product"
      >
        <ProductFormProvider
          key={createDraft?.id ?? "create"}
          onSuccess={onCreateSuccess}
          initialSku={initialSku}
          draft={createDraft ?? undefined}
        >
          <ProductFormModalContent
            onClose={onCloseCreate}
            title="Create Product"
            submitButtonText="Create"
          />
        </ProductFormProvider>
      </AppModal>

      <AppModal
        open={!!editingProduct}
        onOpenChange={(open) => !open && onCloseEdit()}
        title="Edit Product"
      >
        {editingProduct && (
          <ProductFormProvider
            product={editingProduct}
            onSuccess={onEditSuccess}
            onEditSave={onEditSave}
          >
            <ProductFormModalContent
              onClose={onCloseEdit}
              title="Edit Product"
              submitButtonText="Update"
            />
          </ProductFormProvider>
        )}
      </AppModal>

      <AppModal
        open={!!integrationsProduct && !showListProductModal}
        onOpenChange={(open) => !open && onCloseIntegrations()}
        title="Product Listings"
      >
        {integrationsProduct && (
          <ProductListingsModal
            product={integrationsProduct}
            onClose={onCloseIntegrations}
            onStartListing={onStartListing}
            onListingsUpdated={onListingsUpdated}
          />
        )}
      </AppModal>

      <AppModal
        open={!!integrationsProduct && showListProductModal}
        onOpenChange={(open) => !open && onCloseListProduct()}
        title="List Product"
      >
        {integrationsProduct && (
          <ListProductModal
            product={integrationsProduct}
            onClose={onCloseListProduct}
            onSuccess={onListProductSuccess}
            initialIntegrationId={listProductPreset?.integrationId ?? null}
            initialConnectionId={listProductPreset?.connectionId ?? null}
          />
        )}
      </AppModal>

      <AppModal
        open={!!exportSettingsProduct && !!onCloseExportSettings}
        onOpenChange={(open) => !open && onCloseExportSettings?.()}
        title="Export Settings"
      >
        {exportSettingsProduct && onCloseExportSettings && (
          <ProductListingsModal
            product={exportSettingsProduct}
            onClose={onCloseExportSettings}
            filterIntegrationSlug="baselinker"
            onListingsUpdated={onListingsUpdated}
          />
        )}
      </AppModal>

      <AppModal
        open={!!massListIntegration && !!massListProductIds && massListProductIds.length > 0}
        onOpenChange={(open) => !open && onCloseMassList?.()}
        title="Mass List Products"
      >
        {massListIntegration && massListProductIds && onCloseMassList && onMassListSuccess && (
          <MassListProductModal
            integrationId={massListIntegration.integrationId}
            connectionId={massListIntegration.connectionId}
            productIds={massListProductIds}
            onClose={onCloseMassList}
            onSuccess={onMassListSuccess}
          />
        )}
      </AppModal>
    </>
  );
}

"use client";

import { MissingImagePlaceholder } from "@/shared/ui";
import React, { useCallback, useEffect, useRef, useState } from "react";
import Image from "next/image";

interface ProductImageCellProps {
  imageUrl: string | null;
  productName: string;
}

const PREVIEW_SIZE = 136;
const OFFSET_X = 72;
const OFFSET_Y = -90;

export const ProductImageCell = React.memo(function ProductImageCell({
  imageUrl,
  productName,
}: ProductImageCellProps) {
  const [showPreview, setShowPreview] = useState(false);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [viewport, setViewport] = useState({ w: 0, h: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const rafRef = useRef<number | null>(null);
  const pendingPosRef = useRef({ x: 0, y: 0 });

  const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
    pendingPosRef.current = { x: e.clientX, y: e.clientY };
    if (rafRef.current !== null) return;
    rafRef.current = window.requestAnimationFrame(() => {
      setMousePos(pendingPosRef.current);
      rafRef.current = null;
    });
  }, []);

  useEffect(() => {
    const updateViewport = () => {
      setViewport({ w: window.innerWidth, h: window.innerHeight });
    };
    updateViewport();
    window.addEventListener("resize", updateViewport);
    return () => {
      window.removeEventListener("resize", updateViewport);
      if (rafRef.current !== null) {
        window.cancelAnimationFrame(rafRef.current);
        rafRef.current = null;
      }
    };
  }, []);

  if (!imageUrl) {
    return <MissingImagePlaceholder className="size-16" />;
  }

  return (
    <div
      ref={containerRef}
      className="relative"
      onMouseEnter={() => setShowPreview(true)}
      onMouseLeave={() => setShowPreview(false)}
      onMouseMove={handleMouseMove}
    >
      <Image
        src={imageUrl}
        alt={productName}
        width={64}
        height={64}
        className="size-16 rounded-md object-cover cursor-pointer transition-opacity hover:opacity-80"
        style={{ width: "auto", height: "auto" }}
      />

      {showPreview && (
        <div
          className="fixed z-50 pointer-events-none"
          style={{
            left: `${(() => {
              const margin = 8;
              const left = mousePos.x - PREVIEW_SIZE - OFFSET_X;
              const right = mousePos.x + OFFSET_X;
              const fitsLeft = left >= margin;
              const fitsRight = right + PREVIEW_SIZE <= viewport.w - margin;
              if (fitsLeft) return left;
              if (fitsRight) return right;
              return Math.max(margin, Math.min(viewport.w - PREVIEW_SIZE - margin, left));
            })()}px`,
            top: `${(() => {
              const margin = 8;
              const below = mousePos.y + OFFSET_Y;
              const above = mousePos.y - PREVIEW_SIZE - OFFSET_Y;
              const fitsBelow = below + PREVIEW_SIZE <= viewport.h - margin;
              const fitsAbove = above >= margin;
              if (fitsBelow) return below;
              if (fitsAbove) return above;
              return Math.max(margin, Math.min(viewport.h - PREVIEW_SIZE - margin, below));
            })()}px`,
          }}
        >
          <div className="bg-card rounded-lg overflow-hidden shadow-2xl border border-border/60">
            <Image
              src={imageUrl}
              alt={productName}
              width={PREVIEW_SIZE}
              height={PREVIEW_SIZE}
              className="rounded-lg object-cover"
              style={{ width: "auto", height: "auto" }}
              priority
              quality={90}
            />
          </div>
        </div>
      )}
    </div>
  );
});

"use client";

import { useToast, Button, AppModal, Input, Label, Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/shared/ui";
import { useState } from "react";
import { Plus, Trash2 } from "lucide-react";






import type { CatalogRecord } from "@/features/products/types";
import type { ProductParameter } from "@/features/products/types";

type ParametersSettingsProps = {
  loading: boolean;
  parameters: ProductParameter[];
  catalogs: CatalogRecord[];
  selectedCatalogId: string | null;
  onCatalogChange: (catalogId: string) => void;
  onRefresh: () => void;
};

export function ParametersSettings({
  loading,
  parameters,
  catalogs,
  selectedCatalogId,
  onCatalogChange,
  onRefresh,
}: ParametersSettingsProps) {
  const { toast } = useToast();
  const [showModal, setShowModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [editingParameter, setEditingParameter] = useState<ProductParameter | null>(null);
  const [formData, setFormData] = useState({
    name_en: "",
    name_pl: "",
    name_de: "",
    catalogId: "",
  });

  const openCreateModal = () => {
    if (!selectedCatalogId) {
      toast("Please select a catalog first.", { variant: "error" });
      return;
    }
    setEditingParameter(null);
    setFormData({
      name_en: "",
      name_pl: "",
      name_de: "",
      catalogId: selectedCatalogId,
    });
    setShowModal(true);
  };

  const openEditModal = (parameter: ProductParameter) => {
    setEditingParameter(parameter);
    setFormData({
      name_en: parameter.name_en,
      name_pl: parameter.name_pl ?? "",
      name_de: parameter.name_de ?? "",
      catalogId: parameter.catalogId,
    });
    setShowModal(true);
  };

  const handleSave = async () => {
    if (!formData.name_en.trim()) {
      toast("English name is required.", { variant: "error" });
      return;
    }
    if (!formData.catalogId) {
      toast("Catalog is required.", { variant: "error" });
      return;
    }

    setSaving(true);
    try {
      const endpoint = editingParameter
        ? `/api/products/parameters/${editingParameter.id}`
        : "/api/products/parameters";
      const res = await fetch(endpoint, {
        method: editingParameter ? "PUT" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name_en: formData.name_en.trim(),
          name_pl: formData.name_pl.trim() || null,
          name_de: formData.name_de.trim() || null,
          catalogId: formData.catalogId,
        }),
      });
      if (!res.ok) {
        const payload = (await res.json()) as { error?: string };
        throw new Error(payload.error || "Failed to save parameter.");
      }
      toast(editingParameter ? "Parameter updated." : "Parameter created.", {
        variant: "success",
      });
      setShowModal(false);
      onRefresh();
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Failed to save parameter.";
      toast(message, { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (parameter: ProductParameter) => {
    const confirmed = window.confirm(
      `Delete parameter "${parameter.name_en}"?`
    );
    if (!confirmed) return;
    try {
      const res = await fetch(`/api/products/parameters/${parameter.id}`, {
        method: "DELETE",
      });
      if (!res.ok) {
        const payload = (await res.json()) as { error?: string };
        throw new Error(payload.error || "Failed to delete parameter.");
      }
      toast("Parameter deleted.", { variant: "success" });
      onRefresh();
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Failed to delete parameter.";
      toast(message, { variant: "error" });
    }
  };

  const selectedCatalog = catalogs.find(
    (catalog) => catalog.id === selectedCatalogId
  );

  return (
    <div className="space-y-5">
      <div className="rounded-md border border-border bg-card/60 p-4">
        <p className="text-sm font-semibold text-white mb-3">Select Catalog</p>
        <p className="text-xs text-gray-400 mb-3">
          Parameters are managed per catalog.
        </p>
        <div className="w-full max-w-xs">
          <Select
            value={selectedCatalogId || ""}
            onValueChange={onCatalogChange}
          >
            <SelectTrigger>
              <SelectValue placeholder="Select a catalog..." />
            </SelectTrigger>
            <SelectContent>
              {catalogs.map((catalog) => (
                <SelectItem key={catalog.id} value={catalog.id}>
                  {catalog.name}
                  {catalog.isDefault ? " (Default)" : ""}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {selectedCatalogId && (
        <>
          <div className="flex justify-start">
            <Button
              onClick={openCreateModal}
              className="bg-white text-gray-900 hover:bg-gray-200"
            >
              <Plus className="size-4 mr-2" />
              Add Parameter
            </Button>
          </div>

          <div className="rounded-md border border-border bg-card/60 p-4">
            <p className="text-sm font-semibold text-white mb-4">
              Parameters for &quot;{selectedCatalog?.name}&quot;
            </p>

            {loading ? (
              <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
                Loading parameters...
              </div>
            ) : parameters.length === 0 ? (
              <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
                No parameters yet for this catalog. Create your first parameter!
              </div>
            ) : (
              <div className="space-y-2">
                {parameters.map((parameter) => (
                  <div
                    key={parameter.id}
                    className="flex items-center justify-between gap-3 rounded-md border border-border bg-gray-900 px-3 py-2"
                  >
                    <div className="min-w-0">
                      <p className="text-sm text-gray-100 truncate">
                        {parameter.name_en}
                      </p>
                      <div className="text-xs text-gray-400 space-x-2">
                        {parameter.name_pl && (
                          <span>PL: {parameter.name_pl}</span>
                        )}
                        {parameter.name_de && (
                          <span>DE: {parameter.name_de}</span>
                        )}
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Button
                        type="button"
                        onClick={() => openEditModal(parameter)}
                        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-100 hover:bg-gray-700"
                      >
                        Edit
                      </Button>
                      <Button
                        type="button"
                        onClick={() => void handleDelete(parameter)}
                        className="rounded bg-red-600/80 px-2 py-1 text-xs text-white hover:bg-red-600"
                        title="Delete parameter"
                      >
                        <Trash2 className="size-3" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      )}

      {!selectedCatalogId && catalogs.length === 0 && (
        <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
          No catalogs found. Please create a catalog first in the Catalogs section.
        </div>
      )}

      {showModal && (
        <AppModal
          open={showModal}
          onOpenChange={(open) => !open && setShowModal(false)}
          title={editingParameter ? "Edit Parameter" : "Create Parameter"}
        >
          <div className="w-full max-w-md rounded-lg bg-card p-6 shadow-lg">
            <div className="mb-4 flex items-center justify-between">
              <h2 className="text-xl font-semibold text-white">
                {editingParameter ? "Edit Parameter" : "Create Parameter"}
              </h2>
            </div>
            <div className="space-y-3">
              <div>
                <Label className="text-sm">Name (EN)</Label>
                <Input
                  value={formData.name_en}
                  onChange={(event) =>
                    setFormData((prev) => ({
                      ...prev,
                      name_en: event.target.value,
                    }))
                  }
                  placeholder="Parameter name in English"
                />
              </div>
              <div>
                <Label className="text-sm">Name (PL)</Label>
                <Input
                  value={formData.name_pl}
                  onChange={(event) =>
                    setFormData((prev) => ({
                      ...prev,
                      name_pl: event.target.value,
                    }))
                  }
                  placeholder="Optional"
                />
              </div>
              <div>
                <Label className="text-sm">Name (DE)</Label>
                <Input
                  value={formData.name_de}
                  onChange={(event) =>
                    setFormData((prev) => ({
                      ...prev,
                      name_de: event.target.value,
                    }))
                  }
                  placeholder="Optional"
                />
              </div>
            </div>

            <div className="mt-6 flex justify-end gap-2">
              <Button variant="outline" onClick={() => setShowModal(false)}>
                Cancel
              </Button>
              <Button onClick={() => void handleSave()} disabled={saving}>
                {saving ? "Saving..." : "Save"}
              </Button>
            </div>
          </div>
        </AppModal>
      )}
    </div>
  );
}

