"use client";

import { Button, Label, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, Input, useToast, SectionHeader, SectionPanel } from "@/shared/ui";
import { useEffect, useState } from "react";





import { useRouter } from "next/navigation";
import { UserPreferences } from "@/features/products/types";


type Catalog = {
  id: string;
  name: string;
  currencyCode?: string;
};

const DEFAULT_PREFERENCES: UserPreferences = {
  productListNameLocale: "name_en",
  productListCatalogFilter: "all",
  productListCurrencyCode: null,
  productListPageSize: 50,
  aiPathsActivePathId: null,
  aiPathsExpandedGroups: ["Triggers"],
};

export function ProductPreferencesPage() {
  const [preferences, setPreferences] = useState<UserPreferences>(DEFAULT_PREFERENCES);
  const [catalogs, setCatalogs] = useState<Catalog[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const { toast } = useToast();
  const router = useRouter();

  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);

        // Load preferences
        const prefsRes = await fetch("/api/user/preferences");
        if (prefsRes.ok) {
          const prefsData = (await prefsRes.json()) as Partial<UserPreferences>;
          setPreferences({
            productListNameLocale: prefsData.productListNameLocale || "name_en",
            productListCatalogFilter: prefsData.productListCatalogFilter || "all",
            productListCurrencyCode: prefsData.productListCurrencyCode || null,
            productListPageSize: prefsData.productListPageSize || 50,
            aiPathsActivePathId: prefsData.aiPathsActivePathId ?? null,
            aiPathsExpandedGroups: prefsData.aiPathsExpandedGroups ?? ["Triggers"],
          });
        }

        // Load catalogs
        const catalogsRes = await fetch("/api/catalogs");
        if (catalogsRes.ok) {
          const catalogsData = (await catalogsRes.json()) as Catalog[];
          setCatalogs(catalogsData);
        }
      } catch (error) {
        console.error("Failed to load preferences:", error);
        toast("Failed to load preferences", { variant: "error" });
      } finally {
        setLoading(false);
      }
    };

    void loadData();
  }, [toast]);

  const handleSave = async () => {
    try {
      setSaving(true);

      const res = await fetch("/api/user/preferences", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(preferences),
      });

      if (!res.ok) {
        throw new Error("Failed to save preferences");
      }

      toast("Preferences saved successfully", { variant: "success" });
      router.push("/admin/products");
    } catch (error) {
      console.error("Failed to save preferences:", error);
      toast("Failed to save preferences", { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  const handleResetToDefault = async () => {
    try {
      setSaving(true);

      const res = await fetch("/api/user/preferences", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(DEFAULT_PREFERENCES),
      });

      if (!res.ok) {
        throw new Error("Failed to reset preferences");
      }

      setPreferences(DEFAULT_PREFERENCES);
      toast("Preferences reset to default", { variant: "success" });
    } catch (error) {
      console.error("Failed to reset preferences:", error);
      toast("Failed to reset preferences", { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="container mx-auto py-10">
        <div className="rounded-lg bg-card p-6 shadow-lg">
          <p className="text-sm text-gray-400">Loading preferences...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto py-10">
      <SectionPanel className="p-6">
        <SectionHeader
          title="Product Preferences"
          size="md"
          description="Manage your product list display and navigation preferences"
          actions={
            <Button
              variant="outline"
              onClick={() => router.push("/admin/products")}
            >
              Back to Products
            </Button>
          }
          className="mb-6"
        />

        <div className="space-y-6">
          {/* Product List Section */}
          <SectionPanel className="p-6">
            <h2 className="mb-4 text-lg font-semibold text-white">Product List Settings</h2>

            <div className="space-y-4">
              {/* Name Locale */}
              <div className="space-y-2">
                <Label htmlFor="nameLocale">Product Name Language</Label>
                <Select
                  value={preferences.productListNameLocale || "name_en"}
                  onValueChange={(value) =>
                    setPreferences((prev) => ({
                      ...prev,
                      productListNameLocale: value,
                    }))
                  }
                >
                  <SelectTrigger id="nameLocale">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="name_en">English</SelectItem>
                    <SelectItem value="name_pl">Polish</SelectItem>
                    <SelectItem value="name_de">German</SelectItem>
                  </SelectContent>
                </Select>
                <p className="text-xs text-gray-500">
                  Default language for product names in the list
                </p>
              </div>

              {/* Default Catalog Filter */}
              <div className="space-y-2">
                <Label htmlFor="catalogFilter">Default Catalog Filter</Label>
                <Select
                  value={preferences.productListCatalogFilter || "all"}
                  onValueChange={(value) =>
                    setPreferences((prev) => ({
                      ...prev,
                      productListCatalogFilter: value,
                    }))
                  }
                >
                  <SelectTrigger id="catalogFilter">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Catalogs</SelectItem>
                    {catalogs.map((catalog) => (
                      <SelectItem key={catalog.id} value={catalog.id}>
                        {catalog.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <p className="text-xs text-gray-500">
                  Default catalog filter when opening the product list
                </p>
              </div>

              {/* Currency Code */}
              <div className="space-y-2">
                <Label htmlFor="currencyCode">Preferred Currency</Label>
                <Input
                  id="currencyCode"
                  value={preferences.productListCurrencyCode || ""}
                  onChange={(e) =>
                    setPreferences((prev) => ({
                      ...prev,
                      productListCurrencyCode: e.target.value || null,
                    }))
                  }
                  placeholder="EUR, USD, PLN, etc."
                />
                <p className="text-xs text-gray-500">
                  Preferred currency code for price display (leave empty for catalog default)
                </p>
              </div>

              {/* Page Size */}
              <div className="space-y-2">
                <Label htmlFor="pageSize">Products Per Page</Label>
                <Select
                  value={String(preferences.productListPageSize || 50)}
                  onValueChange={(value) =>
                    setPreferences((prev) => ({
                      ...prev,
                      productListPageSize: parseInt(value, 10),
                    }))
                  }
                >
                  <SelectTrigger id="pageSize">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="10">10</SelectItem>
                    <SelectItem value="25">25</SelectItem>
                    <SelectItem value="50">50</SelectItem>
                    <SelectItem value="100">100</SelectItem>
                    <SelectItem value="200">200</SelectItem>
                  </SelectContent>
                </Select>
                <p className="text-xs text-gray-500">
                  Number of products to display per page
                </p>
              </div>
            </div>
          </SectionPanel>

          {/* Action Buttons */}
          <div className="flex justify-between gap-3">
            <Button
              variant="outline"
              onClick={() => void handleResetToDefault()}
              disabled={saving}
              className="border-yellow-600 text-yellow-600 hover:bg-yellow-600/10"
            >
              Reset to Default
            </Button>
            <div className="flex gap-3">
              <Button
                variant="outline"
                onClick={() => router.push("/admin/products")}
                disabled={saving}
              >
                Cancel
              </Button>
              <Button onClick={() => void handleSave()} disabled={saving}>
                {saving ? "Saving..." : "Save Preferences"}
              </Button>
            </div>
          </div>
        </div>
      </SectionPanel>
    </div>
  );
}

import { MissingImagePlaceholder } from "@/shared/ui";
import { productService } from "@/features/products/services/productService";
import Image from "next/image";

import { notFound } from "next/navigation";

export async function ProductPublicPage({
  params,
}: {
  params: { id: string };
}) {
  const { id } = params;
  const product = await productService.getProductById(id);

  if (!product) {
    notFound();
  }

  const title =
    product.name_en ?? product.name_pl ?? product.name_de ?? "Product";

  const imageUrl =
    product.images && product.images.length > 0
      ? product.images[0]!.imageFile.filepath
      : null;

  const priceLabel =
    typeof product.price === "number"
      ? new Intl.NumberFormat("en-US", {
          style: "currency",
          currency: "USD",
        }).format(product.price)
      : "—";

  const description =
    product.description_en ??
    product.description_pl ??
    product.description_de ??
    "";

  return (
    <div className="container mx-auto py-12">
      <div className="grid grid-cols-1 gap-12 md:grid-cols-2">
        <div>
          <div className="relative h-96 w-full">
            {imageUrl ? (
              <Image
                src={imageUrl}
                alt={`${title} image`}
                fill
                className="rounded-lg object-cover"
                sizes="(max-width: 768px) 100vw, 50vw"
              />
            ) : (
              <MissingImagePlaceholder className="h-full w-full rounded-lg" />
            )}
          </div>
        </div>

        <div>
          <h1 className="text-3xl font-bold">{title}</h1>
          <p className="my-4 text-2xl font-semibold">{priceLabel}</p>
          {description ? (
            <p className="text-gray-400">{description}</p>
          ) : (
            <p className="text-gray-500">No description available.</p>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useToast, Button, SectionHeader, SectionPanel } from "@/shared/ui";
import {
  useCallback,
  useEffect,
  useState,
} from "react";

import {
  settingSections,
} from "./ProductSettingsConstants"; // TODO: This is a bit awkward, maybe move constants to feature too
import {
  PriceGroup,
  Catalog,
  ProductCategoryWithChildren,
  ProductTag,
  PriceGroupType,
} from "@/features/products/types";
import type { CurrencyOption, CountryOption, Language } from "@/shared/types/internationalization";

interface ApiPriceGroup extends Omit<PriceGroup, "currencyCode" | "groupType"> {
  currency: { code: string };
  type: PriceGroupType;
}

interface ApiCatalog extends Omit<Catalog, "description" | "priceGroupIds" | "defaultPriceGroupId"> {
  description: string | null;
  priceGroupIds: string[] | null;
  defaultPriceGroupId: string | null;
}

import { PriceGroupsSettings } from "@/features/products/components/settings/pricing/PriceGroupsSettings";
import { CatalogsSettings } from "@/features/products/components/settings/catalogs/CatalogsSettings";
import { CategoriesSettings } from "@/features/products/components/settings/CategoriesSettings";
import { TagsSettings } from "@/features/products/components/settings/TagsSettings";
import { InternationalizationSettings } from "@/features/internationalization";
import { AiDescriptionSettings } from "@/features/products/components/settings/ai/AiDescriptionSettings";
import { AiTranslationSettings } from "@/features/products/components/settings/ai/AiTranslationSettings";

// New Modals
import { CatalogModal } from "@/features/products/components/settings/modals/CatalogModal";
import { LanguageModal } from "@/features/products/components/settings/modals/LanguageModal";
import { PriceGroupModal } from "@/features/products/components/settings/modals/PriceGroupModal";
import { CurrencyModal } from "@/features/products/components/settings/modals/CurrencyModal";
import { CountryModal } from "@/features/products/components/settings/modals/CountryModal";


export function ProductSettingsPage() {
  const [activeSection, setActiveSection] =
    useState<(typeof settingSections)[number]>("Categories");

  // Data State
  const [priceGroups, setPriceGroups] = useState<PriceGroup[]>([]);
  const [productCategories, setProductCategories] = useState<ProductCategoryWithChildren[]>([]);
  const [loadingCategories, setLoadingCategories] = useState(false);
  const [selectedCategoryCatalogId, setSelectedCategoryCatalogId] = useState<string | null>(null);
  const [productTags, setProductTags] = useState<ProductTag[]>([]);
  const [loadingTags, setLoadingTags] = useState(false);
  const [selectedTagCatalogId, setSelectedTagCatalogId] = useState<string | null>(null);
  const [defaultGroupId, setDefaultGroupId] = useState("");
  const [defaultGroupSaving, setDefaultGroupSaving] = useState(false);
  const [currencyOptions, setCurrencyOptions] = useState<CurrencyOption[]>([]);
  const [countries, setCountries] = useState<CountryOption[]>([]);
  const [loadingGroups, setLoadingGroups] = useState(true);
  const [loadingCurrencies, setLoadingCurrencies] = useState(true);
  const [loadingCountries, setLoadingCountries] = useState(true);
  const [loadingCatalogs, setLoadingCatalogs] = useState(true);
  const [catalogs, setCatalogs] = useState<Catalog[]>([]);
  const [languages, setLanguages] = useState<Language[]>([]);
  const [languagesLoading, setLanguagesLoading] = useState(true);
  const [languagesError, setLanguagesError] = useState<string | null>(null);

  // Modal State
  const [showCatalogModal, setShowCatalogModal] = useState(false);
  const [editingCatalog, setEditingCatalog] = useState<Catalog | null>(null);
  const [showLanguageModal, setShowLanguageModal] = useState(false);
  const [editingLanguage, setEditingLanguage] = useState<Language | null>(null);
  const [showPriceGroupModal, setShowPriceGroupModal] = useState(false);
  const [editingPriceGroup, setEditingPriceGroup] = useState<PriceGroup | null>(null);
  const [showCurrencyModal, setShowCurrencyModal] = useState(false);
  const [editingCurrency, setEditingCurrency] = useState<CurrencyOption | null>(null);
  const [showCountryModal, setShowCountryModal] = useState(false);
  const [editingCountry, setEditingCountry] = useState<CountryOption | null>(null);

  const { toast } = useToast();

  const refreshPriceGroups = useCallback(async () => {
    try {
      setLoadingGroups(true);
      const res = await fetch("/api/price-groups");
      if (!res.ok) throw new Error("Failed to fetch price groups.");
      const data = (await res.json()) as ApiPriceGroup[];
      setPriceGroups(
        data.map((group: ApiPriceGroup) => ({
          ...group,
          currencyCode: group.currency.code,
          groupType: group.type,
        }))
      );
      const defaultGroup = data.find((group: ApiPriceGroup) => group.isDefault);
      setDefaultGroupId(defaultGroup?.id ?? "");
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingGroups(false);
    }
  }, []);

  const refreshCurrencies = useCallback(async () => {
    try {
      setLoadingCurrencies(true);
      const res = await fetch("/api/currencies");
      if (!res.ok) throw new Error("Failed to fetch currencies.");
      setCurrencyOptions((await res.json()) as CurrencyOption[]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingCurrencies(false);
    }
  }, []);

  const refreshCountries = useCallback(async () => {
    try {
      setLoadingCountries(true);
      const res = await fetch("/api/countries");
      if (!res.ok) throw new Error("Failed to fetch countries.");
      setCountries((await res.json()) as CountryOption[]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingCountries(false);
    }
  }, []);

  const refreshCatalogs = useCallback(async () => {
    try {
      setLoadingCatalogs(true);
      const res = await fetch("/api/catalogs");
      if (!res.ok) throw new Error("Failed to fetch catalogs.");
      const data = (await res.json()) as ApiCatalog[];
      setCatalogs(
        data.map((catalog: ApiCatalog) => ({
          ...catalog,
          description: catalog.description ?? "",
          priceGroupIds: catalog.priceGroupIds ?? [],
          defaultPriceGroupId: catalog.defaultPriceGroupId ?? null,
        }))
      );
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingCatalogs(false);
    }
  }, []);

  const refreshCategories = useCallback(async (catalogId: string | null) => {
    if (!catalogId) {
      setProductCategories([]);
      return;
    }
    try {
      setLoadingCategories(true);
      const res = await fetch(`/api/products/categories/tree?catalogId=${catalogId}`);
      if (!res.ok) throw new Error("Failed to fetch product categories.");
      setProductCategories((await res.json()) as ProductCategoryWithChildren[]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingCategories(false);
    }
  }, []);

  const refreshTags = useCallback(async (catalogId: string | null) => {
    if (!catalogId) {
      setProductTags([]);
      return;
    }
    try {
      setLoadingTags(true);
      const res = await fetch(`/api/products/tags?catalogId=${catalogId}`);
      if (!res.ok) throw new Error("Failed to fetch product tags.");
      setProductTags((await res.json()) as ProductTag[]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingTags(false);
    }
  }, []);

  const refreshLanguages = useCallback(async () => {
    try {
      setLanguagesLoading(true);
      const res = await fetch("/api/languages");
      if (!res.ok) throw new Error("Failed to fetch languages.");
      setLanguages((await res.json()) as Language[]);
    } catch (error) {
      console.error(error);
      setLanguagesError(error instanceof Error ? error.message : "Failed to fetch languages.");
    } finally {
      setLanguagesLoading(false);
    }
  }, []);

  useEffect(() => {
    void refreshCurrencies();
    void refreshCountries();
    void refreshPriceGroups();
    void refreshCatalogs();
    void refreshLanguages();
  }, [refreshCurrencies, refreshCountries, refreshPriceGroups, refreshCatalogs, refreshLanguages]);

  useEffect(() => {
    if (catalogs.length > 0 && !selectedCategoryCatalogId) {
      const def = catalogs.find((c) => c.isDefault) || catalogs[0];
      if (def) {
        setSelectedCategoryCatalogId(def.id);
        void refreshCategories(def.id);
      }
    }
  }, [catalogs, selectedCategoryCatalogId, refreshCategories]);

  useEffect(() => {
    if (catalogs.length > 0 && !selectedTagCatalogId) {
      const def = catalogs.find((c) => c.isDefault) || catalogs[0];
      if (def) {
        setSelectedTagCatalogId(def.id);
        void refreshTags(def.id);
      }
    }
  }, [catalogs, selectedTagCatalogId, refreshTags]);

  const handleSetDefaultGroup = async (groupId: string) => {
    const group = priceGroups.find((g) => g.id === groupId);
    if (!group) return;
    setDefaultGroupSaving(true);
    try {
      const res = await fetch(`/api/price-groups/${group.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...group, isDefault: true, type: group.groupType }),
      });
      if (res.ok) {
        await refreshPriceGroups();
        toast("Default price group updated.", { variant: "success" });
      }
    } catch (error) {
      console.error(error);
    } finally {
      setDefaultGroupSaving(false);
    }
  };

  const handleDeleteCatalog = async (catalog: Catalog) => {
    if (!confirm(`Delete catalog "${catalog.name}"?`)) return;
    try {
      const res = await fetch(`/api/catalogs/${catalog.id}`, { method: "DELETE" });
      if (res.ok) await refreshCatalogs();
    } catch (err) { console.error(err); }
  };

  const handleDeleteGroup = async (group: PriceGroup) => {
    if (priceGroups.length <= 1) {
      toast("At least one price group is required.", { variant: "error" });
      return;
    }
    if (!confirm(`Delete price group "${group.name}"?`)) return;
    try {
      const res = await fetch(`/api/price-groups/${group.id}`, { method: "DELETE" });
      if (res.ok) await refreshPriceGroups();
    } catch (err) { console.error(err); }
  };

  return (
    <SectionPanel className="p-6">
      <SectionHeader
        title="Product Settings"
        className="mb-6"
      />
      <div className="grid gap-6 md:grid-cols-[240px_1fr]">
        <SectionPanel className="p-4">
          <div className="flex flex-col gap-2">
            {settingSections.map((section) => (
              <Button
                key={section}
                onClick={() => setActiveSection(section)}
                className={`justify-start rounded px-3 py-2 text-left text-sm transition ${
                  activeSection === section
                    ? "bg-gray-800 text-white"
                    : "text-gray-300 hover:bg-muted/50/60"
                }`}
              >
                {section}
              </Button>
            ))}
          </div>
        </SectionPanel>
        <SectionPanel className="p-6">
          {activeSection === "Categories" && (
            <CategoriesSettings
              loading={loadingCategories}
              categories={productCategories}
              catalogs={catalogs}
              selectedCatalogId={selectedCategoryCatalogId}
              onCatalogChange={(id) => { setSelectedCategoryCatalogId(id); void refreshCategories(id); }}
              onRefresh={() => void refreshCategories(selectedCategoryCatalogId)}
            />
          )}
          {activeSection === "Tags" && (
            <TagsSettings
              loading={loadingTags}
              tags={productTags}
              catalogs={catalogs}
              selectedCatalogId={selectedTagCatalogId}
              onCatalogChange={(id) => { setSelectedTagCatalogId(id); void refreshTags(id); }}
              onRefresh={() => void refreshTags(selectedTagCatalogId)}
            />
          )}
          {activeSection === "Price Groups" && (
            <PriceGroupsSettings
              loadingGroups={loadingGroups}
              priceGroups={priceGroups}
              defaultGroupId={defaultGroupId}
              onDefaultGroupChange={(id) => { void handleSetDefaultGroup(id); }}
              defaultGroupSaving={defaultGroupSaving}
              handleOpenCreate={() => { setEditingPriceGroup(null); setShowPriceGroupModal(true); }}
              handleEditGroup={(g) => { setEditingPriceGroup(g); setShowPriceGroupModal(true); }}
              handleDeleteGroup={(g) => { void handleDeleteGroup(g); }}
            />
          )}
          {activeSection === "Catalogs" && (
            <CatalogsSettings
              loadingCatalogs={loadingCatalogs}
              catalogs={catalogs}
              languages={languages}
              handleOpenCatalogModal={() => { setEditingCatalog(null); setShowCatalogModal(true); }}
              handleEditCatalog={(c) => { setEditingCatalog(c); setShowCatalogModal(true); }}
              handleDeleteCatalog={(c) => { void handleDeleteCatalog(c); }}
            />
          )}
          {activeSection === "Internationalization" && (
            <InternationalizationSettings
              loadingCurrencies={loadingCurrencies}
              currencyOptions={currencyOptions}
              handleOpenCurrencyModal={(c) => { setEditingCurrency(c ?? null); setShowCurrencyModal(true); }}
              handleDeleteCurrency={(c) => { 
                void (async () => {
                  if (confirm(`Delete ${c.code}?`)) {
                    await fetch(`/api/currencies/${c.id}`, { method: "DELETE" });
                    await refreshCurrencies();
                  }
                })();
              }}
              loadingCountries={loadingCountries}
              filteredCountries={countries}
              countrySearch=""
              setCountrySearch={() => {}}
              handleOpenCountryModal={(c) => { setEditingCountry(c ?? null); setShowCountryModal(true); }}
              handleDeleteCountry={(c) => {
                void (async () => {
                  if (confirm(`Delete ${c.name}?`)) {
                    await fetch(`/api/countries/${c.id}`, { method: "DELETE" });
                    await refreshCountries();
                  }
                })();
              }}
              languagesLoading={languagesLoading}
              languagesError={languagesError}
              languages={languages}
              handleOpenNewLanguageModal={() => { setEditingLanguage(null); setShowLanguageModal(true); }}
              handleOpenLanguageModal={(l) => { setEditingLanguage(l); setShowLanguageModal(true); }}
              handleDeleteLanguage={(l) => {
                void (async () => {
                  if (confirm(`Delete ${l.name}?`)) {
                    await fetch(`/api/languages/${l.id}`, { method: "DELETE" });
                    await refreshLanguages();
                  }
                })();
              }}
            />
          )}
          {activeSection === "AI Description" && <AiDescriptionSettings />}
          {activeSection === "AI Translation" && <AiTranslationSettings />}
        </SectionPanel>
      </div>

      {/* Modals */}
      <CatalogModal
        isOpen={showCatalogModal}
        onClose={() => setShowCatalogModal(false)}
        onSuccess={() => { void (async () => { setShowCatalogModal(false); await refreshCatalogs(); })(); }}
        catalog={editingCatalog}
        languages={languages}
        languagesLoading={languagesLoading}
        languagesError={languagesError}
        priceGroups={priceGroups}
        loadingGroups={loadingGroups}
        defaultGroupId={defaultGroupId}
      />

      <LanguageModal
        isOpen={showLanguageModal}
        onClose={() => setShowLanguageModal(false)}
        onSuccess={() => { void (async () => { setShowLanguageModal(false); await refreshLanguages(); })(); }}
        language={editingLanguage}
        countries={countries}
      />

      <PriceGroupModal
        isOpen={showPriceGroupModal}
        onClose={() => setShowPriceGroupModal(false)}
        onSuccess={() => { void (async () => { setShowPriceGroupModal(false); await refreshPriceGroups(); })(); }}
        priceGroup={editingPriceGroup}
        currencyOptions={currencyOptions}
        loadingCurrencies={loadingCurrencies}
        priceGroups={priceGroups}
      />

      <CurrencyModal
        isOpen={showCurrencyModal}
        onClose={() => setShowCurrencyModal(false)}
        onSuccess={() => { void (async () => { setShowCurrencyModal(false); await refreshCurrencies(); })(); }}
        currency={editingCurrency}
      />

      <CountryModal
        isOpen={showCountryModal}
        onClose={() => setShowCountryModal(false)}
        onSuccess={() => { void (async () => { setShowCountryModal(false); await refreshCountries(); })(); }}
        country={editingCountry}
        currencyOptions={currencyOptions}
        loadingCurrencies={loadingCurrencies}
      />
    </SectionPanel>
  );
}

import "server-only";

import OpenAI from "openai";
import type { ChatCompletionContentPart } from "openai/resources/chat/completions";
import prisma from "@/shared/lib/db/prisma";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { getImageFileRepository } from "@/features/files/server";
import type { ProductFormData } from "@/features/products/types";
import fs from "fs/promises";
import path from "path";
import {
  badRequestError,
  configurationError,
  operationFailedError,
} from "@/shared/errors/app-error";

const OLLAMA_BASE_URL = process.env.OLLAMA_BASE_URL || "http://localhost:11434";

// AI-related settings that should be read from MongoDB when available
const AI_SETTINGS_KEYS = new Set([
  "ai_vision_model",
  "ai_vision_user_prompt",
  "ai_vision_prompt",
  "ai_vision_output_enabled",
  "openai_model",
  "openai_api_key",
  "description_generation_user_prompt",
  "description_generation_prompt",
  "ai_generation_output_enabled",
]);

interface MongoSetting {
  _id: string;
  value: string;
}

export async function getSettingValue(key: string): Promise<string | null> {
  let value: string | null = null;

  // For AI settings, prefer MongoDB if available
  if (AI_SETTINGS_KEYS.has(key) && process.env.MONGODB_URI) {
    try {
      const mongo = await getMongoDb();
      const doc = await mongo.collection<MongoSetting>("settings").findOne({ _id: key });
      if (doc && typeof doc.value === "string") {
        value = doc.value;
        return value; // Return immediately if found in MongoDB
      }
    } catch (err) {
      console.warn(`Mongo setting fetch failed for ${key}:`, err);
    }
  }

  // Fall back to Prisma
  if (!value && process.env.DATABASE_URL) {
    try {
      const setting = await prisma.setting.findUnique({
        where: { key },
        select: { value: true },
      });
      if (setting) value = setting.value;
    } catch (err) {
      console.warn(`Prisma setting fetch failed for ${key}:`, err);
    }
  }

  // If still not found and not an AI setting, try MongoDB as fallback
  if (!value && !AI_SETTINGS_KEYS.has(key) && process.env.MONGODB_URI) {
    try {
      const mongo = await getMongoDb();
      const doc = await mongo.collection<MongoSetting>("settings").findOne({ _id: key });
      if (doc && typeof doc.value === "string") {
        value = doc.value;
      }
    } catch (err) {
      console.warn(`Mongo fallback setting fetch failed for ${key}:`, err);
    }
  }

  return value;
}

function getClient(modelName: string, apiKey: string | null) {
  // Check if it's a real OpenAI model (not gpt-oss or other Ollama variants)
  const modelLower = modelName.toLowerCase();
  const isOpenAI = (modelLower.startsWith("gpt-") && !modelLower.includes("oss")) ||
                   modelLower.startsWith("ft:gpt-") ||
                   modelLower.startsWith("o1-");

  if (isOpenAI) {
    if (!apiKey) {
      throw configurationError("OpenAI API key is missing for GPT model.");
    }
    return { openai: new OpenAI({ apiKey }), isOllama: false };
  }

  // All other models use Ollama
  return {
    openai: new OpenAI({
      baseURL: `${OLLAMA_BASE_URL}/v1`,
      apiKey: "ollama",
    }),
    isOllama: true
  };
}

export async function generateProductDescription(params: {
  productData: ProductFormData;
  imageUrls?: string[] | undefined;
  visionOutputEnabled?: boolean | undefined;
  generationOutputEnabled?: boolean | undefined;
}) {
  const { productData, imageUrls = [], visionOutputEnabled, generationOutputEnabled } = params;

  if (!productData?.name_en) {
    throw badRequestError("Product name is required", { field: "name_en" });
  }

  const [
    apiKeySetting,
    visionModelSetting,
    visionInputPromptSetting,
    visionOutputPromptSetting,
    visionOutputEnabledSetting,
    generationModelSetting,
    generationInputPromptSetting,
    generationOutputPromptSetting,
    generationOutputEnabledSetting,
  ] = await Promise.all([
    getSettingValue("openai_api_key"),
    getSettingValue("ai_vision_model"),
    getSettingValue("ai_vision_user_prompt"),
    getSettingValue("ai_vision_prompt"),
    getSettingValue("ai_vision_output_enabled"),
    getSettingValue("openai_model"),
    getSettingValue("description_generation_user_prompt"),
    getSettingValue("description_generation_prompt"),
    getSettingValue("ai_generation_output_enabled"),
  ]);

  const apiKey = apiKeySetting ?? process.env.OPENAI_API_KEY ?? null;
  const visionModel = visionModelSetting?.trim() || "gemma3:27b";
  const visionInputPrompt = visionInputPromptSetting?.trim() || "Analyze these product images...";
  const visionOutputPrompt = visionOutputPromptSetting?.trim() || "";
  const isVisionOutputEnabled = visionOutputEnabled !== undefined ? visionOutputEnabled : (visionOutputEnabledSetting === "true");

  const generationModel = generationModelSetting?.trim() || "qwen3-vl:30b";
  const generationInputPrompt = generationInputPromptSetting?.trim() || "Generate description for [name_en]";
  const generationOutputPrompt = generationOutputPromptSetting?.trim() || "";
  const isGenerationOutputEnabled = generationOutputEnabled !== undefined ? generationOutputEnabled : (generationOutputEnabledSetting === "true");

  const processPrompt = (text: string, currentResult: string = "", analysisResult: string = "", descriptionInitial: string = "") => {
    let processed = text;
    const hasImagesPlaceholder = processed.includes("[images]");
    processed = processed.replace(/\[analysis\]/g, analysisResult);
    processed = processed.replace(/\[imageAnalysis\]/g, analysisResult);
    processed = processed.replace(/\[description\]/g, descriptionInitial);
    processed = processed.replace(/\[result\]/g, currentResult);
    processed = processed.replace(/\[initialResult\]/g, currentResult);
    processed = processed.replace(/\[images\]/g, "");

    if (productData) {
      for (const key in productData) {
        if (Object.prototype.hasOwnProperty.call(productData, key)) {
          const value = productData[key as keyof ProductFormData];
          if (value !== null && value !== undefined) {
            const stringValue = typeof value === "object" ? JSON.stringify(value) : String(value);
            processed = processed.replace(new RegExp(`\\[${key}\\]`, 'g'), stringValue);
          }
        }
      }
    }
    return { text: processed.trim(), attachImages: hasImagesPlaceholder };
  };

  let processedImages: ChatCompletionContentPart[] = [];
  if (imageUrls.length > 0) {
    const imageFileRepository = await getImageFileRepository();
    const imageFiles = await imageFileRepository.listImageFiles();
    const imageFileMap = new Map(imageFiles.map((file) => [file.filepath, file]));

    const imagePromises = imageUrls.map(async (item) => {
      try {
        let base64Image: string;
        let mimetype: string = "image/jpeg";
        if (item.startsWith("http")) {
          const res = await fetch(item);
          if (!res.ok) return null;
          const buffer = Buffer.from(await res.arrayBuffer());
          base64Image = buffer.toString("base64");
          mimetype = res.headers.get("content-type") || "image/jpeg";
        } else {
          const imagePath = path.join(process.cwd(), "public", item);
          const buffer = await fs.readFile(imagePath);
          base64Image = buffer.toString("base64");
          const record = imageFileMap.get(item);
          if (record) mimetype = record.mimetype;
        }
        return { type: "image_url" as const, image_url: { url: `data:${mimetype};base64,${base64Image}` } };
      } catch { return null; }
    });
    processedImages = (await Promise.all(imagePromises)).filter((img) => img !== null) as ChatCompletionContentPart[];
  }

  let analysisInitial = "";
  let analysisFinal = "";
  const { openai: visionClient, isOllama: isVisionOllama } = getClient(visionModel, apiKey);

  try {
    const prompt1_1 = processPrompt(visionInputPrompt);
    const content1_1: ChatCompletionContentPart[] = [{ type: "text", text: prompt1_1.text }];
    if (prompt1_1.attachImages) content1_1.push(...processedImages);

    const visionCompletion = await visionClient.chat.completions.create({
      model: visionModel,
      messages: [
        { role: "system", content: "You are an AI assistant." },
        { role: "user", content: content1_1 }
      ],
      max_tokens: 500,
    });
    analysisInitial = visionCompletion.choices[0]?.message.content?.trim() || "";

    if (isVisionOutputEnabled && visionOutputPrompt) {
      const prompt1_2 = processPrompt(visionOutputPrompt, analysisInitial, analysisInitial);
      const content1_2: ChatCompletionContentPart[] = [{ type: "text", text: prompt1_2.text }];
      if (prompt1_2.attachImages) content1_2.push(...processedImages);
      const refineCompletion = await visionClient.chat.completions.create({
        model: visionModel,
        messages: [
          { role: "system", content: "You are an AI assistant." },
          { role: "user", content: content1_2 }
        ],
        max_tokens: 500,
      });
      analysisFinal = refineCompletion.choices[0]?.message.content?.trim() || "";
    }
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    const isConnectionError = errorMessage.includes("ECONNREFUSED") || 
                             errorMessage.includes("fetch failed") || 
                             errorMessage.includes("failed to fetch");

    if (isVisionOllama && isConnectionError) {
      throw operationFailedError(
        `Description generation failed: Could not connect to Ollama server at ${OLLAMA_BASE_URL}. Please ensure the Ollama server is running and accessible.`,
        undefined,
        { originalError: errorMessage, url: OLLAMA_BASE_URL, model: visionModel }
      );
    }
    throw error;
  }

  const visionResultForNext = analysisFinal || analysisInitial;
  const { openai: generationClient, isOllama: isGenerationOllama } = getClient(generationModel, apiKey);
  let descriptionInitial = "";
  let descriptionFinal = "";

  try {
    const prompt2_1 = processPrompt(generationInputPrompt, visionResultForNext, visionResultForNext);
    const content2_1: ChatCompletionContentPart[] = [{ type: "text", text: prompt2_1.text }];
    if (prompt2_1.attachImages) content2_1.push(...processedImages);
    const genCompletion = await generationClient.chat.completions.create({
      model: generationModel,
      messages: [
        { role: "system", content: "You are a helpful assistant." },
        { role: "user", content: content2_1 }
      ],
      max_tokens: 1000,
    });
    descriptionInitial = genCompletion.choices[0]?.message.content?.trim() || "";

    if (isGenerationOutputEnabled && generationOutputPrompt) {
      const prompt2_2 = processPrompt(generationOutputPrompt, descriptionInitial, visionResultForNext, descriptionInitial);
      const content2_2: ChatCompletionContentPart[] = [{ type: "text", text: prompt2_2.text }];
      if (prompt2_2.attachImages) content2_2.push(...processedImages);
      const refineGenCompletion = await generationClient.chat.completions.create({
        model: generationModel,
        messages: [
          { role: "system", content: "You are a helpful assistant." },
          { role: "user", content: content2_2 }
        ],
        max_tokens: 1000,
      });
      descriptionFinal = refineGenCompletion.choices[0]?.message.content?.trim() || "";
    }
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    const isConnectionError = errorMessage.includes("ECONNREFUSED") || 
                             errorMessage.includes("fetch failed") || 
                             errorMessage.includes("failed to fetch");

    if (isGenerationOllama && isConnectionError) {
      throw operationFailedError(
        `Description generation failed: Could not connect to Ollama server at ${OLLAMA_BASE_URL}. Please ensure the Ollama server is running and accessible.`,
        undefined,
        { originalError: errorMessage, url: OLLAMA_BASE_URL, model: generationModel }
      );
    }
    throw error;
  }

  return {
    analysisInitial,
    analysisFinal,
    descriptionInitial,
    descriptionFinal,
    description: descriptionFinal || descriptionInitial,
    analysis: analysisFinal || analysisInitial,
    // Include model information for job tracking
    visionModel,
    generationModel,
    visionOutputEnabled: isVisionOutputEnabled,
    generationOutputEnabled: isGenerationOutputEnabled
  };
}

import OpenAI from "openai";
import {
  apiKeyInvalidError,
  configurationError,
  operationFailedError,
} from "@/shared/errors/app-error";
import { ErrorSystem } from "@/features/observability/server";
import { getSettingValue } from "./aiDescriptionService";

interface TranslateProductParams {
  productId: string;
  sourceLanguage: string;
  targetLanguages: string[];
  productName: string;
  productDescription: string;
}

interface TranslationResult {
  translations: Record<string, {
    name: string;
    description: string;
  }>;
  translationModel?: string;
  targetLanguages?: string[];
  sourceLanguage?: string;
}

const OLLAMA_BASE_URL = process.env.OLLAMA_BASE_URL || "http://localhost:11434";

function getClient(modelName: string, apiKey: string | null) {
  const modelLower = modelName.toLowerCase();
  const isOpenAI = (modelLower.startsWith("gpt-") && !modelLower.includes("oss")) ||
                   modelLower.startsWith("ft:gpt-") ||
                   modelLower.startsWith("o1-");

  if (isOpenAI) {
    if (!apiKey) {
      throw configurationError("OpenAI API key is missing for GPT model.");
    }
    return { openai: new OpenAI({ apiKey }), isOllama: false };
  }

  // All other models use Ollama
  return {
    openai: new OpenAI({
      baseURL: `${OLLAMA_BASE_URL}/v1`,
      apiKey: "ollama",
    }),
    isOllama: true
  };
}

/**
 * Extracts JSON from a string that might contain markdown blocks or other text.
 */
function extractJson(text: string): unknown {
  try {
    // 1. Try direct parse
    return JSON.parse(text);
  } catch (_e) {
    // 2. Try to find JSON block
    const match = text.match(/```json\s*([\s\S]*?)\s*```/) || text.match(/```\s*([\s\S]*?)\s*```/);
    if (match && match[1]) {
      try {
        return JSON.parse(match[1].trim());
      } catch (_e2) {
        // Continue to fallback
      }
    }

    // 3. Try to find anything between { and }
    const firstBrace = text.indexOf('{');
    const lastBrace = text.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
      const candidate = text.substring(firstBrace, lastBrace + 1);
      try {
        return JSON.parse(candidate);
      } catch (_e3) {
        // Continue to fallback
      }
    }

    throw new Error(`Failed to extract valid JSON from response: ${text.substring(0, 100)}...`);
  }
}

export async function translateProduct(params: TranslateProductParams): Promise<TranslationResult> {
  const { sourceLanguage, targetLanguages, productName, productDescription } = params;

  // Load configuration from settings
  const [translationModelSetting, apiKeySetting] = await Promise.all([
    getSettingValue("ai_translation_model"),
    getSettingValue("openai_api_key"),
  ]);

  const translationModel = translationModelSetting?.trim() || "gpt-4o";
  const apiKey = apiKeySetting ?? process.env.OPENAI_API_KEY ?? null;

  console.log(`[aiTranslationService] Using model: ${translationModel}`);

  const { openai, isOllama } = getClient(translationModel, apiKey);

  if (isOllama) {
    console.log(`[aiTranslationService] Using Ollama at: ${OLLAMA_BASE_URL}`);
  }

  console.log(`[aiTranslationService] Target languages: ${targetLanguages.join(", ")}`);
  console.log(`[aiTranslationService] Source language: ${sourceLanguage}`);

  const translations: Record<string, { name: string; description: string }> = {};

  // Translate to each target language
  for (const targetLang of targetLanguages) {
    if (targetLang.toLowerCase() === sourceLanguage.toLowerCase()) {
      console.log(`[aiTranslationService] Skipping ${targetLang} because it is the source language`);
      continue;
    }

    const prompt = `You are a professional translator. Translate the following product information from ${sourceLanguage} to ${targetLang}.

Product Name: ${productName}

Product Description:
${productDescription}

Provide the translation in the following JSON format:
{
  "name": "translated product name",
  "description": "translated product description"
}

Important:
- Maintain the same tone and style
- Keep technical terms accurate
- Preserve any special formatting
- Only respond with the JSON, no additional text`;

    try {
      console.log(`[aiTranslationService] Translating to ${targetLang}...`);

      const options: OpenAI.Chat.ChatCompletionCreateParamsNonStreaming = {
        model: translationModel,
        messages: [
          {
            role: "user",
            content: prompt,
          },
        ],
        temperature: 0.3,
      };

      // Only use response_format for OpenAI models, as Ollama models might not support it reliably via the SDK
      const modelLower = translationModel.toLowerCase();
      const supportsJsonMode = !isOllama && !modelLower.startsWith("o1-");

      if (supportsJsonMode) {
        options.response_format = { type: "json_object" };
      }

      const response = await openai.chat.completions.create(options);

      const content = response.choices[0]?.message?.content;
      if (!content) {
        console.error(`[aiTranslationService] No content in response for ${targetLang}`);
        throw operationFailedError(`No translation received for ${targetLang}`, undefined, {
          targetLanguage: targetLang,
        });
      }

      console.log(`[aiTranslationService] Received response for ${targetLang}`);

      const parsed = extractJson(content) as { name?: string; description?: string };
      translations[targetLang.toLowerCase()] = {
        name: parsed.name || "",
        description: parsed.description || "",
      };

      console.log(`[aiTranslationService] Successfully translated to ${targetLang}`);
    } catch (error) {
      console.error(`[aiTranslationService] Error translating to ${targetLang}:`, error);

      const errorMessage = error instanceof Error ? error.message : "Unknown error";
      const isConnectionError = errorMessage.includes("ECONNREFUSED") || 
                               errorMessage.includes("fetch failed") || 
                               errorMessage.includes("failed to fetch");

      if (isOllama && isConnectionError) {
        throw operationFailedError(
          `Translation failed: Could not connect to Ollama server at ${OLLAMA_BASE_URL}. Please ensure the Ollama server is running and accessible.`,
          undefined,
          { originalError: errorMessage, url: OLLAMA_BASE_URL }
        );
      }

      await ErrorSystem.captureException(error, {
        service: "ai-translation-service",
        targetLanguage: targetLang,
        productName
      });

      // If this is an API key error, throw it to fail the entire job
      if (errorMessage.includes("API key") || errorMessage.includes("401") || errorMessage.includes("authentication")) {
        throw apiKeyInvalidError(
          `Translation failed: ${errorMessage}. Please check your OpenAI API key configuration.`,
          "openai"
        );
      }

      // For other errors, continue with other languages but don't save fallback
      console.warn(`[aiTranslationService] Skipping ${targetLang} due to error`);
    }
  }

  // If no translations were successful, throw an error
  if (Object.keys(translations).length === 0) {
    throw operationFailedError("Translation failed: No translations were completed successfully.");
  }

  return {
    translations,
    translationModel,
    targetLanguages,
    sourceLanguage
  };
}

import "server-only";

import { randomUUID } from "crypto";
import type { WithId } from "mongodb";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import type {
  CatalogCreateInput,
  CatalogRecord,
  CatalogRepository,
  CatalogUpdateInput,
} from "@/features/products/types/services/catalog-repository";

type CatalogDocument = {
  _id: string;
  id: string;
  name: string;
  description: string | null;
  isDefault: boolean;
  defaultLanguageId?: string | null;
  defaultPriceGroupId?: string | null;
  createdAt: Date;
  updatedAt: Date;
  languageIds: string[];
  priceGroupIds?: string[];
};

const CATALOG_COLLECTION = "catalogs";

const toRecord = (doc: WithId<CatalogDocument>): CatalogRecord => ({
  id: doc.id ?? doc._id,
  name: doc.name,
  description: doc.description ?? null,
  isDefault: doc.isDefault,
  defaultLanguageId: doc.defaultLanguageId ?? null,
  defaultPriceGroupId: doc.defaultPriceGroupId ?? null,
  createdAt: doc.createdAt,
  updatedAt: doc.updatedAt,
  languageIds: Array.isArray(doc.languageIds) ? doc.languageIds : [],
  priceGroupIds: Array.isArray(doc.priceGroupIds) ? doc.priceGroupIds : [],
});

export const mongoCatalogRepository: CatalogRepository = {
  async listCatalogs() {
    const db = await getMongoDb();
    const docs = await db
      .collection<CatalogDocument>(CATALOG_COLLECTION)
      .find({})
      .sort({ createdAt: -1 })
      .toArray();
    return docs.map((doc) => toRecord({ ...doc, _id: doc._id }));
  },

  async getCatalogById(id: string) {
    const db = await getMongoDb();
    const doc = await db
      .collection<CatalogDocument>(CATALOG_COLLECTION)
      .findOne({ $or: [{ _id: id }, { id }] });
    return doc ? toRecord({ ...doc, _id: doc._id }) : null;
  },

  async createCatalog(input: CatalogCreateInput) {
    const db = await getMongoDb();
    if (input.isDefault) {
      await db
        .collection<CatalogDocument>(CATALOG_COLLECTION)
        .updateMany({}, { $set: { isDefault: false } });
    }
    const now = new Date();
    const id = randomUUID();
    const doc: CatalogDocument = {
      _id: id,
      id,
      name: input.name,
      description: input.description ?? null,
      isDefault: Boolean(input.isDefault),
      defaultLanguageId: input.defaultLanguageId ?? null,
      defaultPriceGroupId: input.defaultPriceGroupId ?? null,
      createdAt: now,
      updatedAt: now,
      languageIds: input.languageIds ?? [],
      priceGroupIds: input.priceGroupIds ?? [],
    };
    await db.collection<CatalogDocument>(CATALOG_COLLECTION).insertOne(doc);
    return toRecord(doc as WithId<CatalogDocument>);
  },

  async updateCatalog(id: string, input: CatalogUpdateInput) {
    const db = await getMongoDb();
    if (input.isDefault) {
      await db
        .collection<CatalogDocument>(CATALOG_COLLECTION)
        .updateMany({}, { $set: { isDefault: false } });
    }
    const updateDoc: Partial<CatalogDocument> = {
      ...(input.name !== undefined ? { name: input.name } : null),
      ...(input.description !== undefined
        ? { description: input.description ?? null }
        : null),
      ...(input.isDefault !== undefined ? { isDefault: input.isDefault } : null),
      ...(input.defaultLanguageId !== undefined
        ? { defaultLanguageId: input.defaultLanguageId ?? null }
        : null),
      ...(input.defaultPriceGroupId !== undefined
        ? { defaultPriceGroupId: input.defaultPriceGroupId ?? null }
        : null),
      ...(input.languageIds !== undefined
        ? { languageIds: input.languageIds }
        : null),
      ...(input.priceGroupIds !== undefined
        ? { priceGroupIds: input.priceGroupIds }
        : null),
      updatedAt: new Date(),
    };
    const result = await db
      .collection<CatalogDocument>(CATALOG_COLLECTION)
      .findOneAndUpdate(
        { $or: [{ _id: id }, { id }] },
        { $set: updateDoc },
        { returnDocument: "after" }
      );
    return result ? toRecord({ ...result, _id: result._id }) : null;
  },

  async deleteCatalog(id: string) {
    const db = await getMongoDb();
    await db
      .collection<CatalogDocument>(CATALOG_COLLECTION)
      .deleteOne({ $or: [{ _id: id }, { id }] });
  },

  async getCatalogsByIds(ids: string[]) {
    if (ids.length === 0) return [];
    const db = await getMongoDb();
    const docs = await db
      .collection<CatalogDocument>(CATALOG_COLLECTION)
      .find({ $or: [{ _id: { $in: Array.from(ids) } }, { id: { $in: ids } }] })
      .toArray();
    return docs.map((doc) => toRecord({ ...doc, _id: doc._id }));
  },

  async setDefaultCatalog(id: string) {
    const db = await getMongoDb();
    await db
      .collection<CatalogDocument>(CATALOG_COLLECTION)
      .updateMany({}, { $set: { isDefault: false } });
    await db
      .collection<CatalogDocument>(CATALOG_COLLECTION)
      .updateOne(
        { $or: [{ _id: id }, { id }] },
        { $set: { isDefault: true, updatedAt: new Date() } }
      );
  },
};

import "server-only";

import prisma from "@/shared/lib/db/prisma";
import type {
  CatalogCreateInput,
  CatalogRecord,
  CatalogRepository,
  CatalogUpdateInput,
} from "@/features/products/types/services/catalog-repository";

const toRecord = (catalog: {
  id: string;
  name: string;
  description: string | null;
  isDefault: boolean;
  defaultLanguageId: string | null;
  defaultPriceGroupId: string | null;
  priceGroupIds: string[];
  createdAt: Date;
  updatedAt: Date;
  languages?: { languageId: string; position: number }[];
}): CatalogRecord => ({
  id: catalog.id,
  name: catalog.name,
  description: catalog.description ?? null,
  isDefault: catalog.isDefault,
  defaultLanguageId: catalog.defaultLanguageId ?? null,
  defaultPriceGroupId: catalog.defaultPriceGroupId ?? null,
  createdAt: catalog.createdAt,
  updatedAt: catalog.updatedAt,
  // Sort by position to ensure correct ordering
  languageIds: catalog.languages
    ?.sort((a, b) => a.position - b.position)
    .map((entry) => entry.languageId) ?? [],
  priceGroupIds: Array.isArray(catalog.priceGroupIds)
    ? catalog.priceGroupIds
    : [],
});

export const prismaCatalogRepository: CatalogRepository = {
  async listCatalogs() {
    const catalogs = await prisma.catalog.findMany({
      include: {
        languages: {
          select: { languageId: true, position: true },
          orderBy: { position: "asc" },
        },
      },
      orderBy: { createdAt: "desc" },
    });
    return catalogs.map(toRecord);
  },

  async getCatalogById(id: string) {
    const catalog = await prisma.catalog.findUnique({
      where: { id },
      include: {
        languages: {
          select: { languageId: true, position: true },
          orderBy: { position: "asc" },
        },
      },
    });
    return catalog ? toRecord(catalog) : null;
  },

  async createCatalog(input: CatalogCreateInput) {
    if (input.isDefault) {
      await prisma.catalog.updateMany({ data: { isDefault: false } });
    }
    const catalog = await prisma.catalog.create({
      data: {
        name: input.name,
        description: input.description ?? null,
        isDefault: Boolean(input.isDefault),
        defaultLanguageId: input.defaultLanguageId ?? null,
        defaultPriceGroupId: input.defaultPriceGroupId ?? null,
        priceGroupIds: input.priceGroupIds ?? [],
      },
    });
    if (input.languageIds?.length) {
      const existing = await prisma.language.findMany({
        where: { id: { in: input.languageIds } },
        select: { id: true },
      });
      const validIds = new Set(existing.map((entry) => entry.id));
      const languageIds = input.languageIds.filter((id) => validIds.has(id));
      if (languageIds.length > 0) {
        await prisma.catalogLanguage.createMany({
          data: languageIds.map((languageId, index) => ({
            catalogId: catalog.id,
            languageId,
            position: index,
          })),
          skipDuplicates: true,
        });
      }
    }
    const created = await prisma.catalog.findUnique({
      where: { id: catalog.id },
      include: {
        languages: {
          select: { languageId: true, position: true },
          orderBy: { position: "asc" },
        },
      },
    });
    return toRecord(created ?? catalog);
  },

  async updateCatalog(id: string, input: CatalogUpdateInput) {
    if (input.isDefault) {
      await prisma.catalog.updateMany({ data: { isDefault: false } });
    }
    await prisma.catalog.update({
      where: { id },
      data: {
        ...(input.name !== undefined && { name: input.name }),
        ...(input.description !== undefined && {
          description: input.description,
        }),
        ...(input.isDefault !== undefined && { isDefault: input.isDefault }),
        ...(input.defaultLanguageId !== undefined && {
          defaultLanguageId: input.defaultLanguageId,
        }),
        ...(input.defaultPriceGroupId !== undefined && {
          defaultPriceGroupId: input.defaultPriceGroupId,
        }),
        ...(input.priceGroupIds !== undefined && {
          priceGroupIds: input.priceGroupIds,
        }),
      },
    });
    if (input.languageIds) {
      const existing = await prisma.language.findMany({
        where: { id: { in: input.languageIds } },
        select: { id: true },
      });
      const validIds = new Set(existing.map((entry) => entry.id));
      const languageIds = input.languageIds.filter((id) => validIds.has(id));
      await prisma.catalogLanguage.deleteMany({ where: { catalogId: id } });
      if (languageIds.length > 0) {
        await prisma.catalogLanguage.createMany({
          data: languageIds.map((languageId, index) => ({
            catalogId: id,
            languageId,
            position: index,
          })),
          skipDuplicates: true,
        });
      }
    }
    const updated = await prisma.catalog.findUnique({
      where: { id },
      include: {
        languages: {
          select: { languageId: true, position: true },
          orderBy: { position: "asc" },
        },
      },
    });
    return updated ? toRecord(updated) : null;
  },

  async deleteCatalog(id: string) {
    await prisma.catalog.delete({ where: { id } });
  },

  async getCatalogsByIds(ids: string[]) {
    if (ids.length === 0) return [];
    const catalogs = await prisma.catalog.findMany({
      where: { id: { in: ids } },
      include: {
        languages: {
          select: { languageId: true, position: true },
          orderBy: { position: "asc" },
        },
      },
    });
    return catalogs.map(toRecord);
  },

  async setDefaultCatalog(id: string) {
    await prisma.catalog.updateMany({ data: { isDefault: false } });
    await prisma.catalog.update({ where: { id }, data: { isDefault: true } });
  },
};

