import { cn } from "@/shared/utils";

export interface Asset3DCardProps {
  asset: Asset3DRecord;
  onPreview: (asset: Asset3DRecord) => void;
  onEdit: (asset: Asset3DRecord) => void;
  onDelete: (asset: Asset3DRecord) => void;
  isDeleting?: boolean;
  className?: string;
}

export function Asset3DCard({
  asset,
  onPreview,
  onEdit,
  onDelete,
  isDeleting = false,
  className,
}: Asset3DCardProps) {
  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / 1024 / 1024).toFixed(2)} MB`;
  };

  const formatDate = (date: Date | string) => {
    return new Date(date).toLocaleDateString("en-US", {
      year: "numeric",
      month: "short",
      day: "numeric",
    });
  };

  const displayName = asset.name || asset.filename.replace(/^\d+-/, "");

  return (
    <div
      className={cn(
        "rounded-lg border border-border bg-card/60 overflow-hidden transition-colors group hover:border-blue-500/60",
        className
      )}
    >
      {/* Preview Area */}
      <div
        className="h-40 bg-muted/30 flex items-center justify-center cursor-pointer relative"
        onClick={() => onPreview(asset)}
      >
        <div className="flex flex-col items-center gap-2 text-muted-foreground group-hover:text-blue-400 transition-colors">
          <Box className="h-12 w-12" />
          <span className="text-xs flex items-center gap-1">
            <Eye className="h-3 w-3" />
            Click to preview
          </span>
        </div>

        {/* Visibility Badge */}
        <div
          className={cn(
            "absolute top-2 right-2 px-2 py-1 rounded text-xs flex items-center gap-1",
            asset.isPublic
              ? "bg-emerald-500/10 text-emerald-400"
              : "bg-muted text-muted-foreground"
          )}
        >
          {asset.isPublic ? (
            <>
              <Globe className="h-3 w-3" />
              Public
            </>
          ) : (
            <>
              <Lock className="h-3 w-3" />
              Private
            </>
          )}
        </div>

        {/* Category Badge */}
        {asset.category && (
          <div className="absolute top-2 left-2 px-2 py-1 rounded text-xs bg-blue-500/10 text-blue-300">
            {asset.category}
          </div>
        )}
      </div>

      {/* Info */}
      <div className="p-3">
        <div className="flex items-start justify-between gap-2">
          <div className="min-w-0 flex-1">
            <p
              className="text-sm font-medium text-foreground truncate"
              title={displayName}
            >
              {displayName}
            </p>
            {asset.description && (
              <p
                className="text-xs text-muted-foreground truncate mt-0.5"
                title={asset.description}
              >
                {asset.description}
              </p>
            )}
          </div>
        </div>

        {/* Tags */}
        {asset.tags.length > 0 && (
          <div className="flex flex-wrap gap-1 mt-2">
            {asset.tags.slice(0, 3).map((tag) => (
              <span
                key={tag}
                className="px-1.5 py-0.5 text-xs bg-muted text-muted-foreground rounded"
              >
                {tag}
              </span>
            ))}
            {asset.tags.length > 3 && (
              <span className="px-1.5 py-0.5 text-xs bg-muted text-muted-foreground rounded">
                +{asset.tags.length - 3}
              </span>
            )}
          </div>
        )}

        {/* Meta & Actions */}
        <div className="flex items-center justify-between mt-3 pt-2 border-t border-border">
          <div className="text-xs text-muted-foreground">
            <span>{formatFileSize(asset.size)}</span>
            <span className="mx-1">•</span>
            <span>{formatDate(asset.createdAt)}</span>
          </div>
          <div className="flex items-center gap-1">
            <Button
              variant="ghost"
              size="icon"
              className="h-7 w-7 text-muted-foreground hover:text-blue-400"
              onClick={(e) => {
                e.stopPropagation();
                onEdit(asset);
              }}
            >
              <Edit2 className="h-4 w-4" />
            </Button>
            <Button
              variant="ghost"
              size="icon"
              className="h-7 w-7 text-muted-foreground hover:text-red-400"
              onClick={(e) => {
                e.stopPropagation();
                onDelete(asset);
              }}
              disabled={isDeleting}
            >
              {isDeleting ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Trash2 className="h-4 w-4" />
              )}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

import {
  AppError,
  AppErrorCodes,
  authError,
  badRequestError,
  conflictError,
  createAppError,
  externalServiceError,
  forbiddenError,
  isAppError,
  notFoundError,
  rateLimitedError,
  serviceUnavailableError,
  timeoutError,
  unprocessableEntityError,
  databaseError,
} from "@/shared/errors/app-error";

export type MapStatusOptions = {
  retryAfterMs?: number;
};

const safeMessage = (message: string | null | undefined, fallback: string) =>
  message && message.trim() ? message : fallback;

export const mapStatusToAppError = (
  message: string,
  status: number,
  options?: MapStatusOptions
): AppError => {
  const msg = safeMessage(message, "Request failed");
  if (status === 400) return badRequestError(msg);
  if (status === 401) return authError(msg);
  if (status === 403) return forbiddenError(msg);
  if (status === 404) return notFoundError(msg);
  if (status === 409) return conflictError(msg);
  if (status === 422) return unprocessableEntityError(msg);
  if (status === 429) return rateLimitedError(msg, options?.retryAfterMs);
  if (status === 503) return serviceUnavailableError(msg, options?.retryAfterMs);
  if (status === 504) return timeoutError(msg);
  if (status >= 500) {
    return externalServiceError(msg, { status });
  }
  if (status >= 400) {
    return createAppError(msg, {
      code: AppErrorCodes.badRequest,
      httpStatus: status,
      expected: true,
    });
  }
  return createAppError(msg, {
    code: AppErrorCodes.internal,
    httpStatus: 500,
    expected: false,
  });
};

const NETWORK_ERROR_CODES = new Set([
  "ECONNREFUSED",
  "ECONNRESET",
  "EAI_AGAIN",
  "ENOTFOUND",
  "ETIMEDOUT",
  "ECONNABORTED",
]);

export const mapErrorToAppError = (
  error: unknown,
  fallbackMessage?: string
): AppError | null => {
  if (isAppError(error)) return error;

  if (error && typeof error === "object") {
    const err = error as {
      name?: string;
      message?: string;
      status?: number;
      statusCode?: number;
      code?: string | number;
      retryAfterMs?: number;
      retryAfter?: number;
    };

    const status =
      typeof err.status === "number"
        ? err.status
        : typeof err.statusCode === "number"
          ? err.statusCode
          : null;

    if (status !== null) {
      const retryAfterMs =
        typeof err.retryAfterMs === "number"
          ? err.retryAfterMs
          : typeof err.retryAfter === "number"
            ? err.retryAfter * 1000
            : undefined;
      return mapStatusToAppError(err.message ?? fallbackMessage ?? "Request failed", status, {
        ...(typeof retryAfterMs === "number" ? { retryAfterMs } : {}),
      });
    }

    if (err.name === "AbortError") {
      return timeoutError(fallbackMessage ?? "Operation timed out");
    }

    if (err.name && err.name.toLowerCase().includes("mongo")) {
      const codeNumber = typeof err.code === "number" ? err.code : Number(err.code);
      const message = err.message ?? "";
      if (codeNumber === 11000 || message.includes("E11000") || message.includes("duplicate key")) {
        return conflictError("Duplicate entry", {
          mongoCode: err.code,
        });
      }
      if (codeNumber === 121) {
        return unprocessableEntityError("Document validation failed", {
          mongoCode: err.code,
        });
      }
      if (err.name.includes("Network") || err.name.includes("ServerSelection")) {
        return databaseError("Database connection failed", error);
      }
      if (err.name.includes("Timeout") || message.toLowerCase().includes("timed out")) {
        return timeoutError("Database operation timed out", { mongoCode: err.code });
      }
      return databaseError(fallbackMessage ?? "Database operation failed", error, {
        mongoCode: err.code,
      });
    }

    if (typeof err.code === "string" && NETWORK_ERROR_CODES.has(err.code)) {
      return externalServiceError(
        fallbackMessage ?? "Network error",
        { code: err.code },
        { retryable: true }
      );
    }

    if (err.name === "SyntaxError" && (err.message ?? "").includes("JSON")) {
      return badRequestError("Invalid JSON payload");
    }
  }

  return null;
};

import { useState, useCallback } from "react";

interface UseUndoResult<T> {
  state: T;
  setState: (newState: T, skipHistory?: boolean) => void;
  undo: () => void;
  redo: () => void;
  canUndo: boolean;
  canRedo: boolean;
  resetHistory: (initialState: T) => void;
}

export function useUndo<T>(initialState: T, limit: number = 50): UseUndoResult<T> {
  const [state, setInnerState] = useState<T>(initialState);
  const [history, setHistory] = useState<T[]>([initialState]);
  const [index, setIndex] = useState(0);

  // We use a ref to track if we should merge rapid updates (optional, usually good for typing)
  // For now, straightforward implementation.

  const setState = useCallback(
    (newState: T, skipHistory = false) => {
      setInnerState(newState);

      if (skipHistory) return;

      setHistory((prev) => {
        const currentHistory = prev.slice(0, index + 1);
        const nextHistory = [...currentHistory, newState];
        if (nextHistory.length > limit) {
          nextHistory.shift();
          setIndex((i) => i); // Index stays same relative to end, but since we shifted... wait.
          // If we shift, index should arguably decrease? No, we are appending.
          // If length 51, limit 50. Remove 0. Index was 49 (end). New item at 50.
          // Slice 1..51. New index 49.
          return nextHistory;
        }
        return nextHistory;
      });
      setIndex((prev) => {
        const next = prev + 1;
        return next >= limit ? limit - 1 : next;
      });
    },
    [index, limit]
  );

  const undo = useCallback(() => {
    if (index > 0) {
      setIndex((prev) => prev - 1);
      setInnerState(history[index - 1]!);
    }
  }, [history, index]);

  const redo = useCallback(() => {
    if (index < history.length - 1) {
      setIndex((prev) => prev + 1);
      setInnerState(history[index + 1]!);
    }
  }, [history, index]);

  const resetHistory = useCallback((newState: T) => {
    setInnerState(newState);
    setHistory([newState]);
    setIndex(0);
  }, []);

  return {
    state,
    setState,
    undo,
    redo,
    canUndo: index > 0,
    canRedo: index < history.length - 1,
    resetHistory,
  };
}

"use client";

import { useQuery, useMutation, useQueryClient, type UseQueryResult, type UseMutationResult } from "@tanstack/react-query";
import type { SystemSetting } from "@/shared/types/settings";

export type { SystemSetting };

export function useSettings(): UseQueryResult<SystemSetting[], Error> {
  return useQuery({
    queryKey: ["settings"],
    queryFn: async (): Promise<SystemSetting[]> => {
      const res = await fetch("/api/settings");
      if (!res.ok) throw new Error("Failed to fetch settings");
      return (await res.json()) as SystemSetting[];
    },
    staleTime: 0,
  });
}

export function useSettingsMap(): UseQueryResult<Map<string, string>, Error> {
  return useQuery({
    queryKey: ["settings"],
    queryFn: async (): Promise<SystemSetting[]> => {
      const res = await fetch("/api/settings");
      if (!res.ok) throw new Error("Failed to fetch settings");
      return (await res.json()) as SystemSetting[];
    },
    select: (data: SystemSetting[]): Map<string, string> => new Map(data.map((item) => [item.key, item.value])),
    staleTime: 0,
  });
}

export function useUpdateSetting(): UseMutationResult<SystemSetting, Error, { key: string; value: string }> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ key, value }: { key: string; value: string }): Promise<SystemSetting> => {
      const res = await fetch("/api/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ key, value }),
      });
      if (!res.ok) throw new Error("Failed to update setting");
      return (await res.json()) as SystemSetting;
    },
    onSuccess: (): void => {
      void queryClient.invalidateQueries({ queryKey: ["settings"] });
    },
  });
}

export function useUpdateSettingsBulk(): UseMutationResult<Response[], Error, Array<{ key: string; value: string }>> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (payloads: Array<{ key: string; value: string }>): Promise<Response[]> => {
      const responses = await Promise.all(
        payloads.map((payload) =>
          fetch("/api/settings", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload),
          })
        )
      );
      if (responses.some((res) => !res.ok)) {
        throw new Error("Failed to update settings");
      }
      return responses;
    },
    onSuccess: (): void => {
      void queryClient.invalidateQueries({ queryKey: ["settings"] });
    },
  });
}

import "server-only";

import { MongoClient } from "mongodb";

let client: MongoClient | null = null;
let clientPromise: Promise<MongoClient> | null = null;

const getMongoUri = () => {
  const uri = process.env.MONGODB_URI;
  if (!uri) {
    throw new Error("MONGODB_URI is not set.");
  }
  return uri;
};

export async function getMongoClient() {
  if (client) return client;
  if (!clientPromise) {
    clientPromise = new MongoClient(getMongoUri()).connect();
  }
  client = await clientPromise;
  return client;
}

export async function getMongoDb() {
  const dbName = process.env.MONGODB_DB || "app";
  const mongoClient = await getMongoClient();
  return mongoClient.db(dbName);
}

import "server-only";

import { PrismaClient } from "@prisma/client";
import { PrismaPg } from "@prisma/adapter-pg";
import { Pool } from "pg";

const databaseUrl = process.env.DATABASE_URL;

const prisma = databaseUrl
  ? new PrismaClient({
      adapter: new PrismaPg(new Pool({ connectionString: databaseUrl })),
    })
  : (new Proxy(
      {},
      {
        get() {
          throw new Error("DATABASE_URL is not set");
        },
        has() {
          return false;
        },
      }
    ) as unknown as PrismaClient);

export default prisma;

import "server-only";

import { createHash } from "crypto";
import type { SystemLogLevel, SystemLogRecord } from "@/shared/types/system-logs";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import prisma from "@/shared/lib/db/prisma";
import { getAppDbProvider } from "@/shared/lib/db/app-db-provider";
import { withTransientRecovery } from "@/shared/utils/transient-recovery";

const SETTINGS_COLLECTION = "settings";

const NOTIFICATION_SETTINGS_KEYS = {
  enabled: "critical_notifications_enabled",
  webhookUrl: "critical_notifications_webhook_url",
  minLevel: "critical_notifications_min_level",
  throttleSeconds: "critical_notifications_throttle_seconds",
} as const;

const DEFAULT_THROTTLE_SECONDS = 120;

type NotificationConfig = {
  enabled: boolean;
  webhookUrl: string | null;
  minLevel: SystemLogLevel;
  throttleSeconds: number;
};

type SettingRecord = { _id: string; key?: string; value?: string };

const canUsePrismaSettings = () =>
  Boolean(process.env.DATABASE_URL) && "setting" in prisma;

const readPrismaSetting = async (key: string): Promise<string | null> => {
  if (!canUsePrismaSettings()) return null;
  try {
    const setting = await prisma.setting.findUnique({
      where: { key },
      select: { value: true },
    });
    return setting?.value ?? null;
  } catch {
    return null;
  }
};

const readMongoSetting = async (key: string): Promise<string | null> => {
  if (!process.env.MONGODB_URI) return null;
  const mongo = await getMongoDb();
  const doc = await mongo
    .collection<SettingRecord>(SETTINGS_COLLECTION)
    .findOne({ $or: [{ _id: key }, { key }] });
  return typeof doc?.value === "string" ? doc.value : null;
};

const readSettingValue = async (key: string): Promise<string | null> => {
  const provider = await getAppDbProvider();
  if (provider === "mongodb") {
    return readMongoSetting(key);
  }
  return readPrismaSetting(key);
};

const parseBoolean = (value: string | null | undefined, fallback = false) => {
  if (typeof value !== "string") return fallback;
  return value.trim().toLowerCase() === "true";
};

const parseNumber = (value: string | null | undefined, fallback: number) => {
  if (typeof value !== "string") return fallback;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const parseMinLevel = (value: string | null | undefined): SystemLogLevel => {
  const normalized = value?.trim().toLowerCase();
  if (normalized === "warn") return "warn";
  if (normalized === "info") return "info";
  return "error";
};

const levelPriority: Record<SystemLogLevel, number> = {
  info: 1,
  warn: 2,
  error: 3,
};

const shouldNotifyForLevel = (level: SystemLogLevel, minLevel: SystemLogLevel) =>
  levelPriority[level] >= levelPriority[minLevel];

const getNotificationConfig = async (): Promise<NotificationConfig> => {
  const [enabledSetting, webhookSetting, minLevelSetting, throttleSetting] = await Promise.all([
    readSettingValue(NOTIFICATION_SETTINGS_KEYS.enabled),
    readSettingValue(NOTIFICATION_SETTINGS_KEYS.webhookUrl),
    readSettingValue(NOTIFICATION_SETTINGS_KEYS.minLevel),
    readSettingValue(NOTIFICATION_SETTINGS_KEYS.throttleSeconds),
  ]);

  const enabled =
    parseBoolean(enabledSetting) ||
    parseBoolean(process.env.CRITICAL_ERROR_NOTIFICATIONS_ENABLED);
  const webhookUrl = webhookSetting ?? process.env.CRITICAL_ERROR_WEBHOOK_URL ?? null;
  const minLevel = parseMinLevel(minLevelSetting ?? process.env.CRITICAL_ERROR_MIN_LEVEL);
  const throttleSeconds = parseNumber(
    throttleSetting ?? process.env.CRITICAL_ERROR_THROTTLE_SECONDS,
    DEFAULT_THROTTLE_SECONDS
  );

  return {
    enabled,
    webhookUrl,
    minLevel,
    throttleSeconds,
  };
};

const getThrottleCache = (): Map<string, number> => {
  const globalAny = globalThis as typeof globalThis & {
    __criticalErrorNotificationCache?: Map<string, number>;
  };
  if (!globalAny.__criticalErrorNotificationCache) {
    globalAny.__criticalErrorNotificationCache = new Map();
  }
  return globalAny.__criticalErrorNotificationCache;
};

const buildSignature = (log: SystemLogRecord) => {
  const hash = createHash("sha256");
  hash.update(log.message ?? "");
  hash.update(String(log.source ?? ""));
  hash.update(String(log.path ?? ""));
  hash.update(String(log.statusCode ?? ""));
  return hash.digest("hex");
};

const shouldThrottle = (signature: string, throttleSeconds: number) => {
  const cache = getThrottleCache();
  const now = Date.now();
  const previous = cache.get(signature);
  if (previous && now - previous < throttleSeconds * 1000) {
    return true;
  }
  cache.set(signature, now);
  return false;
};

const buildPayload = (log: SystemLogRecord, critical: boolean) => ({
  event: "critical_error",
  critical,
  level: log.level,
  message: log.message,
  source: log.source ?? null,
  path: log.path ?? null,
  method: log.method ?? null,
  statusCode: log.statusCode ?? null,
  requestId: log.requestId ?? null,
  userId: log.userId ?? null,
  createdAt: log.createdAt instanceof Date ? log.createdAt.toISOString() : log.createdAt,
  context: log.context ?? null,
  stack: log.stack ?? null,
  environment: process.env.NODE_ENV ?? "development",
  appUrl: process.env.NEXT_PUBLIC_APP_URL ?? null,
});

export const notifyCriticalError = async (
  log: SystemLogRecord,
  critical: boolean
): Promise<{ delivered: boolean; throttled: boolean }> => {
  try {
    const config = await getNotificationConfig();
    if (!config.enabled || !config.webhookUrl) {
      return { delivered: false, throttled: false };
    }
    if (!shouldNotifyForLevel(log.level, config.minLevel)) {
      return { delivered: false, throttled: false };
    }
    if (!critical) {
      return { delivered: false, throttled: false };
    }

    const signature = buildSignature(log);
    if (shouldThrottle(signature, config.throttleSeconds)) {
      return { delivered: false, throttled: true };
    }

    const payload = buildPayload(log, critical);
    const res = await withTransientRecovery(
      async () =>
        fetch(config.webhookUrl!, {
          method: "POST",
          headers: {
            "content-type": "application/json",
          },
          body: JSON.stringify(payload),
        }),
      {
        source: "critical-error-webhook",
        circuitId: "critical-error-webhook",
        retry: {
          maxAttempts: 3,
          initialDelayMs: 1000,
          maxDelayMs: 10000,
          timeoutMs: 8000,
        },
      }
    );
    if (!res.ok) {
      console.error("[critical-error-notifier] Webhook failed", {
        status: res.status,
        statusText: res.statusText,
      });
      return { delivered: false, throttled: false };
    }
    return { delivered: true, throttled: false };
  } catch (error) {
    console.error("[critical-error-notifier] Webhook error", error);
    return { delivered: false, throttled: false };
  }
};

const SENSITIVE_KEY_PATTERNS = [
  /pass(word)?/i,
  /token/i,
  /secret/i,
  /api[-_]?key/i,
  /authorization/i,
  /^cookie$/i,
  /^set-cookie$/i,
  /session/i,
  /jwt/i,
  /private/i,
  /credential/i,
];

export const REDACTED_VALUE = "[REDACTED]";

export const isSensitiveKey = (key: string) =>
  SENSITIVE_KEY_PATTERNS.some((pattern) => pattern.test(key));

export const truncateString = (value: string, maxLength: number) => {
  if (value.length <= maxLength) return value;
  return `${value.slice(0, maxLength)}…[truncated]`;
};
